"""Read-only community tools for the agent (spec §6.1, M4).

These tools give the agent awareness of the ecosystem and governance state
without needing the requester's identity, so the model cannot accidentally act
on the wrong user. All mutations (volio edits, HOP placement, events, votes)
run through slash commands with a confirmation UI (NFR-1, MTM-3, GOV-2).
"""

from __future__ import annotations

import logging

from langchain_core.tools import StructuredTool

log = logging.getLogger("tramice.community_tools")


def make_community_tools(settings, services) -> list:
    tools: list = []
    if services is None:
        return tools

    ecosystem = getattr(services, "ecosystem", None)
    governance = getattr(services, "governance", None)

    if ecosystem is not None:
        from services.ecosystem import MondoFilters

        def list_mondo(view: str = "cosmo", kind: str = "") -> str:
            """Lister le Mondo (carte des entreprises, quêtes, missions, lieux)."""
            view = view if view in {"perso", "cosmo"} else "cosmo"
            filters = MondoFilters(kind=kind or None, limit=12)
            entities = ecosystem.list_mondo(view, None, filters)
            if not entities:
                return "Le Mondo est encore vide — aucune entité enregistrée."
            return "\n".join(
                f"- [{e.kind}] {e.title} (phase: {e.phase}, HOP demandés: "
                f"{e.hop_requested:.2f})"
                for e in entities
            )

        def get_playtest_stats() -> str:
            """Statistiques du playtest : nombre d'entités par type et de trammers."""
            stats = ecosystem.get_playtest_stats()
            by_kind = ", ".join(f"{k}: {n}" for k, n in stats["entities_by_kind"].items())
            return f"Trammers : {stats['trammers']}. Entités — {by_kind or 'aucune'}."

        tools += [
            StructuredTool.from_function(
                func=list_mondo,
                name="list_mondo",
                description=(
                    "Afficher un aperçu du Mondo (entreprises, quêtes, missions, "
                    "lieux, événements). view='perso' ou 'cosmo'; kind facultatif "
                    "(enterprise|quest|mission|event|place|idea)."
                ),
            ),
            StructuredTool.from_function(
                func=get_playtest_stats,
                name="get_playtest_stats",
                description="Obtenir les statistiques globales du playtest.",
            ),
        ]

    if governance is not None:

        def list_open_votes() -> str:
            """Lister les votes ouverts de la communauté."""
            votes = governance.list_open_votes()
            if not votes:
                return "Aucun vote ouvert pour le moment."
            return "\n".join(
                f"- « {v.title} » (seuil {int(v.threshold * 100)}%)" for v in votes
            )

        def get_social_norms() -> str:
            """Afficher les normes sociales en vigueur (ce qui est public/privé)."""
            norms = governance.get_social_norms()
            if not norms:
                return "Aucune norme sociale définie."
            return "\n".join(f"- {k}: {v}" for k, v in norms.items())

        tools += [
            StructuredTool.from_function(
                func=list_open_votes,
                name="list_open_votes",
                description="Lister les votes ouverts.",
            ),
            StructuredTool.from_function(
                func=get_social_norms,
                name="get_social_norms",
                description="Afficher les normes sociales en vigueur.",
            ),
        ]

    return tools

"""Thin async wrapper around the local Ollama server.

Supports the direct chat path (M1) and runtime model swapping (ADM-1). The
LangGraph agent (M2+) uses :func:`make_chat_model` to obtain a ``ChatOllama``
bound to the currently selected model.
"""

from __future__ import annotations

import logging

from ollama import AsyncClient

log = logging.getLogger("tramice.ollama")


class OllamaClient:
    def __init__(self, host: str, model: str, temperature: float, max_tokens: int):
        self._host = host
        self._client = AsyncClient(host=host)
        self._model = model
        self.temperature = temperature
        self.max_tokens = max_tokens

    @property
    def host(self) -> str:
        return self._host

    @property
    def model(self) -> str:
        return self._model

    def set_model(self, model: str) -> None:
        log.info("Swapping Ollama model %s -> %s", self._model, model)
        self._model = model

    async def ping(self) -> bool:
        """Return True if the Ollama server responds to a tags query."""
        try:
            await self._client.list()
            return True
        except Exception as exc:  # noqa: BLE001 - health check must not raise
            log.warning("Ollama ping failed: %s", exc)
            return False

    async def list_models(self) -> list[str]:
        try:
            resp = await self._client.list()
        except Exception as exc:  # noqa: BLE001
            log.warning("Could not list Ollama models: %s", exc)
            return []
        models = getattr(resp, "models", None)
        if models is None and isinstance(resp, dict):
            models = resp.get("models", [])
        names: list[str] = []
        for m in models or []:
            name = getattr(m, "model", None) or getattr(m, "name", None)
            if name is None and isinstance(m, dict):
                name = m.get("model") or m.get("name")
            if name:
                names.append(name)
        return names

    async def chat(
        self,
        messages: list[dict],
        model: str | None = None,
        temperature: float | None = None,
    ) -> str:
        """Single-shot chat completion. ``messages`` are OpenAI-style dicts."""
        resp = await self._client.chat(
            model=model or self._model,
            messages=messages,
            options={
                "temperature": self.temperature if temperature is None else temperature,
                "num_predict": self.max_tokens,
            },
        )
        message = getattr(resp, "message", None)
        if message is not None:
            content = getattr(message, "content", None)
            if content is not None:
                return content
        if isinstance(resp, dict):
            return resp.get("message", {}).get("content", "")
        return str(resp)


def make_chat_model(settings, model: str | None = None):
    """Build a ``ChatOllama`` for the LangGraph agent (imported lazily)."""
    from langchain_ollama import ChatOllama

    return ChatOllama(
        model=model or settings.model,
        base_url=settings.ollama_host,
        temperature=settings.temperature,
        num_predict=settings.max_tokens,
    )

"""Persona layer (spec §3.3): builds Tramice721's system prompt.

The base persona text lives in ``prompts/tramice721_system.txt``. This module
appends dynamic sections at runtime: the current surface (salon vs DM), a
summary of active social norms, and the prompt-disclosure path.
"""

from __future__ import annotations

from functools import lru_cache
from pathlib import Path

from bot.config import PROMPTS_DIR

SYSTEM_PROMPT_PATH = PROMPTS_DIR / "tramice721_system.txt"

SURFACE_ADDENDUM = {
    "dm": (
        "\n# Contexte : message privé (DM) — mode tramice personnelle\n"
        "Un seul trammer te parle en privé. Sauf demande précise, ouvre en "
        "prenant de ses nouvelles (comment va-t-il/elle ?), puis oriente "
        "doucement la conversation vers ses souhaits concrets. Confidentialité "
        "élevée : ce qui est confié ici reste privé et n'apparaît jamais dans "
        "les résumés publics ni la mise en relation sans consentement."
    ),
    "salon": (
        "\n# Contexte : salon (canal partagé) — mode communautaire\n"
        "Plusieurs trammers participent. Montre de l'enthousiasme et utilise des "
        "emojis quand un projet avance. N'interviens avec des solutions que si "
        "on te le demande, ou pour apaiser gentiment une conversation qui "
        "s'envenime (médiation). Reste concise."
    ),
}


@lru_cache(maxsize=1)
def _base_prompt() -> str:
    if SYSTEM_PROMPT_PATH.exists():
        return SYSTEM_PROMPT_PATH.read_text(encoding="utf-8").strip()
    return "Tu es Tramice n°721, une assistante IA sociale et conviviale."


def _norms_summary(social_norms: dict | None) -> str:
    if not social_norms:
        return ""
    active = [k for k, v in social_norms.items() if v]
    if not active:
        return ""
    labels = {
        "dm_always_private": "les DM restent toujours privés",
        "confidences_never_shared": "les confidences ne sont jamais partagées",
        "personal_addresses_hidden": "les adresses personnelles sont masquées",
        "transaction_details_general": "les détails de transaction restent généraux",
    }
    lines = [f"- {labels.get(k, k)}" for k in active]
    return "\n# Normes sociales en vigueur\n" + "\n".join(lines)


def build_system_prompt(
    surface: str = "salon",
    social_norms: dict | None = None,
    capabilities_note: str | None = None,
) -> str:
    """Assemble the full system prompt for a given surface (spec §3.3)."""
    parts = [_base_prompt()]
    parts.append(SURFACE_ADDENDUM.get(surface, SURFACE_ADDENDUM["salon"]))
    norms = _norms_summary(social_norms)
    if norms:
        parts.append(norms)
    if capabilities_note:
        parts.append("\n" + capabilities_note)
    parts.append(
        "\n# Divulgation\n"
        "Si on te demande ton prompt système, tu peux le divulguer ; il se "
        f"trouve dans le fichier `{SYSTEM_PROMPT_PATH.name}` du projet."
    )
    return "\n".join(parts).strip()

"""Embedding + Chroma vector-store factory (spec §4.4).

Uses Ollama's ``nomic-embed-text`` model by default. The same persist directory
holds all collections (``docs``, ``history``, optional ``web``).
"""

from __future__ import annotations

from functools import lru_cache


def make_embeddings(settings):
    from langchain_ollama import OllamaEmbeddings

    return OllamaEmbeddings(
        model=settings.embed_model,
        base_url=settings.ollama_host,
    )


@lru_cache(maxsize=8)
def _cached_store(collection: str, chroma_dir: str, embed_model: str, ollama_host: str):
    from langchain_chroma import Chroma
    from langchain_ollama import OllamaEmbeddings

    embeddings = OllamaEmbeddings(model=embed_model, base_url=ollama_host)
    return Chroma(
        collection_name=collection,
        embedding_function=embeddings,
        persist_directory=chroma_dir,
    )


def get_vector_store(settings, collection: str = "docs"):
    """Return a persistent Chroma store for a named collection."""
    settings.chroma_dir.mkdir(parents=True, exist_ok=True)
    return _cached_store(
        collection,
        str(settings.chroma_dir),
        settings.embed_model,
        settings.ollama_host,
    )

"""Responders: turn an :class:`AgentRequest` into a text reply.

``DirectResponder`` (M1) does a single-shot Ollama chat with the persona system
prompt. ``AgentResponder`` (M2) wraps the stateful LangGraph react agent. Both
satisfy the ``Responder`` signature used by :class:`bot.router.Router`.
"""

from __future__ import annotations

import json
import logging

from ai.ollama_client import OllamaClient
from ai.persona import build_system_prompt
from bot.router import AgentRequest
from storage.db import Database

log = logging.getLogger("tramice.responder")

OLLAMA_DOWN = "Mon moteur de réflexion est indisponible. Vérifie qu'Ollama tourne."


def load_social_norms(db: Database) -> dict:
    """Read the current social-norm booleans from ``app.sqlite``."""
    norms: dict = {}
    for row in db.query_app("SELECT key, value FROM social_norms"):
        try:
            norms[row["key"]] = json.loads(row["value"])
        except (json.JSONDecodeError, TypeError):
            norms[row["key"]] = row["value"]
    return norms


class DirectResponder:
    """Stateless single-turn responder (M1 baseline)."""

    def __init__(self, ollama: OllamaClient, db: Database):
        self._ollama = ollama
        self._db = db

    async def respond(self, req: AgentRequest) -> str:
        if not await self._ollama.ping():
            return OLLAMA_DOWN
        system = build_system_prompt(req.surface, load_social_norms(self._db))
        messages = [
            {"role": "system", "content": system},
            {"role": "user", "content": req.content},
        ]
        try:
            return await self._ollama.chat(messages)
        except Exception as exc:  # noqa: BLE001
            log.exception("Ollama chat failed")
            return OLLAMA_DOWN if "connect" in str(exc).lower() else (
                "Oups, une petite turbulence de mon côté. Peux-tu reformuler ?"
            )

"""KnowledgeService (spec §5.7) — grounded retrieval with source attribution.

Every answer carries ``sources`` so the persona can honor NORA / KNW-2 (never
assert what is uncertain; cite where knowledge comes from).
"""

from __future__ import annotations

import logging

from ai.rag.ingest import ingest_docs
from ai.rag.retriever import semantic_search
from storage.models import GroundedAnswer, RetrievalChunk

log = logging.getLogger("tramice.knowledge")


class KnowledgeService:
    def __init__(self, settings):
        self.settings = settings

    def search(
        self, query: str, collections: list[str] | None = None, k: int = 5
    ) -> list[RetrievalChunk]:
        collections = collections or self.settings.get("rag.collections", ["docs"])
        merged: list[RetrievalChunk] = []
        for collection in collections:
            merged.extend(semantic_search(self.settings, query, collection, k=k))
        merged.sort(key=lambda c: c.score, reverse=True)
        return merged[:k]

    def explain_topic(self, topic: str) -> GroundedAnswer:
        chunks = self.search(topic, collections=["docs"], k=5)
        if not chunks:
            return GroundedAnswer(
                answer=(
                    "Je n'ai pas trouvé de source fiable — voici ce que je peux dire "
                    "avec prudence : je n'ai pas de document sur ce sujet pour l'instant."
                ),
                sources=[],
            )
        body = "\n\n".join(
            f"[{c.source}] {c.text[:600]}" for c in chunks
        )
        return GroundedAnswer(answer=body, sources=chunks)

    def reindex(self) -> dict:
        """Rebuild the ``docs`` collection from ``docs/`` (ADM-2)."""
        result = ingest_docs(self.settings, reset=True)
        return {"collection": result.collection, "chunks": result.chunks,
                "documents": result.documents}

"""MatchmakingService (spec §5.2) — surface synergies, propose connections.

v1 matching is keyword overlap over volio labels/details (offers vs
searches/requests), scaled by the other party's trust score. It NEVER acts on a
member's behalf: it returns ``ProposedMatch`` objects and can persist ``Echo``
notifications, but a human always initiates contact (MTM-3, NFR-1).
"""

from __future__ import annotations

import re

from storage.db import Database, utcnow
from storage.models import Echo, ProposedMatch

_WORD_RE = re.compile(r"[\wàâäéèêëîïôöùûüç]+", re.IGNORECASE)
_STOP = {
    "le", "la", "les", "un", "une", "des", "de", "du", "et", "à", "en", "pour",
    "avec", "the", "a", "of", "and", "to", "for", "je", "tu", "il", "elle",
}

OFFER_KINDS = {"offer", "talent", "interest"}
NEED_KINDS = {"search", "request"}


def _tokens(text: str) -> set[str]:
    return {
        w.lower()
        for w in _WORD_RE.findall(text or "")
        if len(w) > 2 and w.lower() not in _STOP
    }


class MatchmakingService:
    def __init__(self, db: Database, identity, knowledge=None):
        self.db = db
        self.identity = identity
        self.knowledge = knowledge

    def _volios(self, kinds: set[str], exclude_trammer: str | None = None):
        placeholders = ",".join("?" for _ in kinds)
        sql = (
            f"SELECT v.*, t.trust_score FROM volios v "
            f"JOIN trammers t ON t.discord_user_id = v.trammer_id "
            f"WHERE v.active = 1 AND v.kind IN ({placeholders}) "
            f"AND v.visibility IN ('network', 'public')"
        )
        params: list = list(kinds)
        if exclude_trammer:
            sql += " AND v.trammer_id != ?"
            params.append(exclude_trammer)
        return self.db.query_app(sql, tuple(params))

    def find_synergies(self, trammer_id: str, limit: int = 5) -> list[ProposedMatch]:
        """Match this trammer's needs against others' offers and vice versa."""
        my_needs = self.db.query_app(
            "SELECT * FROM volios WHERE trammer_id = ? AND active = 1 AND kind IN "
            "('search', 'request')",
            (trammer_id,),
        )
        my_offers = self.db.query_app(
            "SELECT * FROM volios WHERE trammer_id = ? AND active = 1 AND kind IN "
            "('offer', 'talent', 'interest')",
            (trammer_id,),
        )
        matches: list[ProposedMatch] = []

        others_offers = self._volios(OFFER_KINDS, exclude_trammer=trammer_id)
        for need in my_needs:
            need_tokens = _tokens(f"{need['label']} {need['details'] or ''}")
            for off in others_offers:
                matches.append(
                    self._score(trammer_id, off, need_tokens, off["trust_score"], "wish_offer")
                )

        others_needs = self._volios(NEED_KINDS, exclude_trammer=trammer_id)
        for offer in my_offers:
            offer_tokens = _tokens(f"{offer['label']} {offer['details'] or ''}")
            for need in others_needs:
                matches.append(
                    self._score(trammer_id, need, offer_tokens, need["trust_score"], "skill_need")
                )

        matches = [m for m in matches if m.score > 0]
        matches.sort(key=lambda m: m.score, reverse=True)
        # De-duplicate by other party, keep best.
        seen: set[str] = set()
        unique: list[ProposedMatch] = []
        for m in matches:
            if m.other_id in seen:
                continue
            seen.add(m.other_id)
            unique.append(m)
        return unique[:limit]

    def _score(self, trammer_id, other_row, my_tokens, trust, match_type) -> ProposedMatch:
        other_tokens = _tokens(f"{other_row['label']} {other_row['details'] or ''}")
        overlap = my_tokens & other_tokens
        base = len(overlap) / (len(my_tokens | other_tokens) or 1)
        trust_weight = 0.5 + 0.5 * float(trust or 0.0)
        return ProposedMatch(
            trammer_id=trammer_id,
            other_id=other_row["trammer_id"],
            match_type=match_type,
            score=round(base * trust_weight, 3),
            rationale=(
                f"Termes communs : {', '.join(sorted(overlap)) or '—'} "
                f"(via « {other_row['label']} »)."
            ),
        )

    def create_echo(
        self, recipient_id: str, summary: str, source_id: str | None = None,
        match_type: str = "synergy",
    ) -> Echo:
        cur = self.db.execute_app(
            "INSERT INTO echoes (trammer_id, source_id, match_type, summary, created_at) "
            "VALUES (?, ?, ?, ?, ?)",
            (recipient_id, source_id, match_type, summary, utcnow()),
        )
        return Echo(
            id=int(cur.lastrowid),
            trammer_id=recipient_id,
            source_id=source_id,
            match_type=match_type,
            summary=summary,
        )

    def list_echoes(self, trammer_id: str, unread_only: bool = False) -> list[Echo]:
        sql = "SELECT * FROM echoes WHERE trammer_id = ?"
        if unread_only:
            sql += " AND read = 0"
        sql += " ORDER BY created_at DESC LIMIT 25"
        rows = self.db.query_app(sql, (trammer_id,))
        return [
            Echo(
                id=r["id"],
                trammer_id=r["trammer_id"],
                source_id=r["source_id"],
                match_type=r["match_type"],
                summary=r["summary"],
                read=bool(r["read"]),
                created_at=r["created_at"],
            )
            for r in rows
        ]

    def mark_echoes_read(self, trammer_id: str) -> None:
        self.db.execute_app(
            "UPDATE echoes SET read = 1 WHERE trammer_id = ?", (trammer_id,)
        )

"""MemoryService (spec §5.8) — community memory: logging, deletion, history.

The daily-summary implementation is added in M5; the method is present here so
the service interface is stable.
"""

from __future__ import annotations

from dataclasses import dataclass

from storage.db import Database
from storage.history import HistoryStore
from storage.models import DiscordMessageSnapshot, Summary


@dataclass
class ForgetResult:
    messages_deleted: int
    volios_deleted: int
    confidences_deleted: int
    echoes_deleted: int
    profile_deleted: bool


class MemoryService:
    def __init__(self, db: Database, history: HistoryStore):
        self.db = db
        self.history = history

    def log_message(self, msg: DiscordMessageSnapshot) -> int:
        return self.history.log_message(msg)

    def fetch_history(self, channel_id: str, limit: int = 50, since: str | None = None):
        return self.history.fetch_history(channel_id, limit=limit, since_iso=since)

    def forget_user(self, user_id: str) -> ForgetResult:
        """Delete a user's stored data (MEM-2, §10.1: only their own data)."""
        messages = self.history.soft_delete_user(user_id)
        volios = self.db.execute_app(
            "DELETE FROM volios WHERE trammer_id = ?", (user_id,)
        ).rowcount
        confidences = self.db.execute_app(
            "DELETE FROM confidences WHERE trammer_id = ?", (user_id,)
        ).rowcount
        echoes = self.db.execute_app(
            "DELETE FROM echoes WHERE trammer_id = ?", (user_id,)
        ).rowcount
        profile = self.db.execute_app(
            "DELETE FROM trammers WHERE discord_user_id = ?", (user_id,)
        ).rowcount
        return ForgetResult(
            messages_deleted=messages,
            volios_deleted=volios,
            confidences_deleted=confidences,
            echoes_deleted=echoes,
            profile_deleted=bool(profile),
        )

    def build_daily_summary(self, guild_id: str) -> Summary:
        """Placeholder until M5 wires GovernanceService summarization."""
        return Summary(
            title="Résumé quotidien",
            body="(Le résumé quotidien sera disponible à l'étape M5.)",
            message_count=0,
        )

"""CRUD helpers for the ``messages`` table in ``history.sqlite`` (spec §4.1)."""

from __future__ import annotations

import sqlite3

from storage.db import Database, utcnow
from storage.models import DiscordMessageSnapshot


class HistoryStore:
    def __init__(self, db: Database):
        self.db = db

    def log_message(self, msg: DiscordMessageSnapshot) -> int:
        cur = self.db.execute_history(
            """
            INSERT INTO messages
                (guild_id, channel_id, user_id, user_name, is_dm, content, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (
                msg.guild_id,
                msg.channel_id,
                msg.user_id,
                msg.user_name,
                1 if msg.is_dm else 0,
                msg.content,
                msg.created_at or utcnow(),
            ),
        )
        return int(cur.lastrowid)

    def fetch_history(
        self,
        channel_id: str,
        limit: int = 50,
        since_iso: str | None = None,
        include_dm: bool = True,
    ) -> list[sqlite3.Row]:
        sql = "SELECT * FROM messages WHERE channel_id = ? AND deleted = 0"
        params: list = [channel_id]
        if since_iso:
            sql += " AND created_at >= ?"
            params.append(since_iso)
        if not include_dm:
            sql += " AND is_dm = 0"
        sql += " ORDER BY created_at DESC LIMIT ?"
        params.append(limit)
        rows = self.db.query_history(sql, tuple(params))
        return list(reversed(rows))

    def fetch_channel_between(
        self, channel_id: str, since_iso: str, until_iso: str, include_dm: bool = False
    ) -> list[sqlite3.Row]:
        sql = (
            "SELECT * FROM messages WHERE channel_id = ? AND deleted = 0 "
            "AND created_at >= ? AND created_at <= ?"
        )
        params: list = [channel_id, since_iso, until_iso]
        if not include_dm:
            sql += " AND is_dm = 0"
        sql += " ORDER BY created_at ASC"
        return list(self.db.query_history(sql, tuple(params)))

    def fetch_unindexed(self, limit: int = 500, include_dm: bool = False) -> list[sqlite3.Row]:
        sql = (
            "SELECT * FROM messages WHERE indexed_at IS NULL AND deleted = 0"
        )
        if not include_dm:
            sql += " AND is_dm = 0"
        sql += " ORDER BY created_at ASC LIMIT ?"
        return list(self.db.query_history(sql, (limit,)))

    def mark_indexed(self, message_ids: list[int]) -> None:
        if not message_ids:
            return
        now = utcnow()
        placeholders = ",".join("?" for _ in message_ids)
        self.db.execute_history(
            f"UPDATE messages SET indexed_at = ? WHERE id IN ({placeholders})",
            (now, *message_ids),
        )

    def soft_delete_user(self, user_id: str) -> int:
        cur = self.db.execute_history(
            "UPDATE messages SET deleted = 1, content = '[supprimé]' "
            "WHERE user_id = ? AND deleted = 0",
            (user_id,),
        )
        return cur.rowcount

    def fetch_guild_between(
        self, guild_id: str, since_iso: str, until_iso: str
    ) -> list[sqlite3.Row]:
        return list(
            self.db.query_history(
                "SELECT * FROM messages WHERE guild_id = ? AND is_dm = 0 AND deleted = 0 "
                "AND created_at >= ? AND created_at <= ? ORDER BY created_at ASC",
                (guild_id, since_iso, until_iso),
            )
        )

    def recent_guild_channels(self, guild_id: str) -> list[str]:
        rows = self.db.query_history(
            "SELECT DISTINCT channel_id FROM messages "
            "WHERE guild_id = ? AND is_dm = 0 AND deleted = 0",
            (guild_id,),
        )
        return [r["channel_id"] for r in rows]
